noncompliant:
class A {
public:
    int value;
};

class B1 : public virtual A {  // Virtual inheritance
};

class B2 : public virtual A {  // Virtual inheritance
};

class B3 : public A {          // Non-virtual inheritance
};

// Noncompliant - A is both virtual (through B1, B2) and non-virtual (through B3)
class C : public B1, public B2, public B3 {
    // This creates multiple copies of A
};

compliant:
class A {
public:
    int value;
};

class B1 : public virtual A {  // Virtual inheritance
};

class B2 : public virtual A {  // Virtual inheritance
};

class B3 : public virtual A {  // Virtual inheritance - consistent
};

// Compliant - all inheritance of A is virtual
class C : public B1, public B2, public B3 {
    // Only one copy of A exists
};

// Alternative compliant solution - all non-virtual
class D1 : public A {
};

class D2 : public A {
};

class D : public D1, public D2 {
    // Multiple copies of A, but consistently non-virtual
};
